// === NORMALIZE / MAP ========================================================
// >>> THE ONLY LAYER YOU TOUCH TO GO LIVE. <<<
// Maps the incoming (ASSUMED) Tekmetric payload -> our internal field names.
// When the real Tekmetric webhook schema is known, change ONLY this node:
// point each field below at the real path. Nothing downstream changes.
//
// n8n version note: the Webhook node may expose the POSTed JSON under
// $json.body (most versions) OR directly on $json. We handle BOTH here so
// this workflow is version-safe (verified against the live payload, not guessed).
const out = [];
for (const item of items) {
  const root = (item.json && item.json.body) ? item.json.body : item.json;
  const d    = (root && root.data) ? root.data : {};
  const ro   = (root && root.repair_order) ? root.repair_order : {};
  const shop = (root && root.shop) ? root.shop : {};
  out.push({ json: {
    event_type:    root.event_type || '',
    ro_number:     ro.number || (ro.id != null ? String(ro.id) : '?'),
    shop_name:     shop.name || '',
    from_status:   d.from_status || '',
    to_status:     d.to_status || '',
    author:        d.author || '',
    note:          d.note || '',
    inspector:     d.inspector || '',
    flagged_items: (d.flagged_items != null ? d.flagged_items : 0),
    job_name:      d.job_name || '',
    technician:    d.technician || '',
  }});
}
return out;

// === BUILD: ro_status_changed (MEDIUM importance, blue) =====================
// >>> TRANSITION FILTER LIVES HERE <<<
// Only notify on MAJOR transitions. Trivial moves are noise -> skipped by
// returning no item (nothing flows on to Mattermost for those).
const MAJOR = ['In Progress', 'Completed'];
const out = [];
for (const item of items) {
  const j = item.json;
  if (!MAJOR.includes(j.to_status)) {
    continue; // trivial transition -> skip, no notification
  }
  out.push({ json: {
    channel: 'shop-floor',
    username: 'Tekmetric Bot',
    icon_emoji: ':wrench:',
    text: '🔧 RO #' + j.ro_number + ' — status: ' + j.from_status + ' → ' + j.to_status,
    attachments: [{ color: '#3498db', text: 'Status change · ' + j.shop_name }],
  }});
}
return out;

// === BUILD: tech_note_added (MEDIUM importance, blue) =======================
const out = [];
for (const item of items) {
  const j = item.json;
  out.push({ json: {
    channel: 'shop-floor',
    username: 'Tekmetric Bot',
    icon_emoji: ':wrench:',
    text: '📝 ' + j.author + ' added a note on RO #' + j.ro_number,
    attachments: [{ color: '#3498db', text: j.note }],
  }});
}
return out;

// === BUILD: inspection_finished (HIGH importance, green) ====================
// High-priority: a colored attachment that stands out. This directly triggers
// "a human should call the customer next".
const out = [];
for (const item of items) {
  const j = item.json;
  out.push({ json: {
    channel: 'shop-floor',
    username: 'Tekmetric Bot',
    icon_emoji: ':wrench:',
    text: '✅ Inspection finished — RO #' + j.ro_number + ' (' + j.flagged_items + ' items flagged)',
    attachments: [{
      color: '#2ecc71',
      title: '✅ Inspection finished — RO #' + j.ro_number,
      text: j.flagged_items + ' item(s) flagged · by ' + j.inspector,
    }],
  }});
}
return out;

// === BUILD: job_completed (HIGH importance, green) ==========================
const out = [];
for (const item of items) {
  const j = item.json;
  out.push({ json: {
    channel: 'shop-floor',
    username: 'Tekmetric Bot',
    icon_emoji: ':checkered_flag:',
    text: '🏁 Job completed — RO #' + j.ro_number + ' ("' + j.job_name + '")',
    attachments: [{
      color: '#2ecc71',
      title: '🏁 Job completed — RO #' + j.ro_number,
      text: '"' + j.job_name + '" · by ' + j.technician,
    }],
  }});
}
return out;
